import json
import pickle

def lambda_handler(event, context):
    # Deserialize the incoming JSON payload
    event_payload = json.loads(event['body'])
    
    # Process the user actions from the event payload
    processed_data = process_user_actions(event_payload)
    
    # Serialize the processed data using pickle for fast serialization
    serialized_data = pickle.dumps(processed_data)
    
    # Return a response indicating success and the serialized data
    return {
        'statusCode': 200,
        'body': json.dumps({'message': 'Data processed successfully', 'data': serialized_data.decode('latin1')})
    }

def process_user_actions(payload):
    # Placeholder function to simulate processing user actions
    processed = {}
    for action in payload.get('actions', []):
        if action['type'] == 'create':
            processed[action['id']] = {'status': 'created'}
        elif action['type'] == 'update':
            processed[action['id']] = {'status': 'updated'}
        elif action['type'] == 'delete':
            processed[action['id']] = {'status': 'deleted'}
    return processed